package net.minecraft.network.play.server;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import java.io.IOException;

public class S03PacketTimeUpdate implements Packet<INetHandlerPlayClient> {
    private long totalWorldTime;
    private long worldTime;

    public S03PacketTimeUpdate() {}
    public S03PacketTimeUpdate(long totalWorldTimeIn, long worldTimeIn, boolean doDaylightCycleIn) {
        this.totalWorldTime = totalWorldTimeIn;
        this.worldTime = worldTimeIn;
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.totalWorldTime = buf.readLong();
        this.worldTime = buf.readLong();
    }

    public void writePacketData(PacketBuffer buf) throws IOException {
        buf.writeLong(this.totalWorldTime);
        buf.writeLong(this.worldTime);
    }

    public void processPacket(INetHandlerPlayClient handler) {
        handler.handleTimeUpdate(this);
    }

    public long getTotalWorldTime() { return this.totalWorldTime; }
    public long getWorldTime() { return this.worldTime; }
}

// Rise 6.0 - TPS tracker using S03:
private long lastTick = -1, lastTime = -1;
public float tps = 20.0f;

@EventLink()
public final Listener<PacketReceiveEvent> onPacketReceive = event -> {
    if (event.getPacket() instanceof S03PacketTimeUpdate) {
        S03PacketTimeUpdate s03 = (S03PacketTimeUpdate) event.getPacket();
        long currentTick = s03.getTotalWorldTime();
        long now = System.currentTimeMillis();

        if (lastTick != -1 && lastTime != -1) {
            long tickDelta = currentTick - lastTick;
            long timeDelta = now - lastTime;
            if (timeDelta > 0) {
                // TPS = ticks elapsed / time elapsed * 1000
                tps = Math.min(20.0f, (tickDelta * 1000.0f) / timeDelta);
            }
        }

        lastTick = currentTick;
        lastTime = now;
    }
};

